// Array of premium colors for the avatars
const avatarColors = ['#f44336', '#e91e63', '#9c27b0', '#673ab7', '#3f51b5', '#2196f3', '#03a9f4', '#009688', '#4caf50', '#ff9800', '#ff5722'];

// Function to generate initials (e.g., "Ankit Singh" -> "AS")
function getInitials(name) {
  let parts = name.split(' ');
  let initials = parts[0][0];
  if (parts.length > 1) initials += parts[1][0];
  return initials.toUpperCase();
}

// Function to pick a consistent color based on the user's name length
function getColor(name) {
  let index = name.length % avatarColors.length;
  return avatarColors[index];
}

// Wait for the page to load
document.addEventListener('DOMContentLoaded', () => {
  const track = document.getElementById('reviewsTrack');
  const dotsContainer = document.getElementById('carouselDots');
  const counterDisplay = document.getElementById('carouselCounter');
  const playPauseBtn = document.getElementById('playPauseBtn');
  
  if (!track) return;

  const totalReviews = reviewsData.length;
  let currentIndex = 0;
  let autoScrollInterval;
  let isUserPaused = false; // Tracks if the user manually clicked pause

  // 1. Generate Cards & Dots
  reviewsData.forEach((review, index) => {
    // Generate Stars
    let starsHtml = '';
    for(let i=0; i<review.rating; i++) {
      starsHtml += '<i class="fa-solid fa-star"></i>';
    }

    // Create Card
    const card = document.createElement('div');
    card.className = 'review-card';
// Check if the user has a real profile photo
    let avatarHtml = '';
    if (review.photoUrl && review.photoUrl.trim() !== '') {
      avatarHtml = `<img src="${review.photoUrl}" alt="${review.name}" style="width: 100%; height: 100%; border-radius: 50%; object-fit: cover;">`;
    } else {
      // Fallback to the colored initials we built earlier
      avatarHtml = `
        <div style="background-color: ${getColor(review.name)}; width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; border-radius: 50%;">
          ${getInitials(review.name)}
        </div>`;
    }

    // Inject into the card
    card.innerHTML = `
      <div class="review-header">
        <div class="review-avatar" style="width: 45px; height: 45px;">
          ${avatarHtml}
        </div>
        <div class="review-author">
          <div class="author-name">${review.name}</div>
        </div>
      </div>
      <div class="review-meta">
        <div class="review-stars">${starsHtml}</div>
        <div class="review-time">${review.time}</div>
      </div>
      <div class="review-body">
        <p class="review-text">${review.text}</p>
        <button class="show-more-btn">Show more</button>
      </div>
      <div class="review-footer">
        Posted on <img src="assets/google-logo.svg" alt="Google" class="google-logo-sm">
      </div>
    `;
    track.appendChild(card);

    // Create Dot (Limit to max 20 dots so it doesn't clutter)
    if (dotsContainer && index < 20) {
      const dot = document.createElement('div');
      dot.className = `carousel-dot ${index === 0 ? 'active' : ''}`;
      dot.addEventListener('click', () => {
        isUserPaused = true; // Stop auto-scroll if user clicks a dot
        updatePlayPauseIcon();
        scrollToReview(index);
      });
      dotsContainer.appendChild(dot);
    }
  });

  // 2. Logic & Auto-Scroller Functions
  const cardWidth = 364; // 340px width + 24px gap

  function updateControls() {
    // Update Counter Text
    if (counterDisplay) counterDisplay.innerText = `${currentIndex + 1} / ${totalReviews}`;
    
    // Update Active Dot
    if (dotsContainer) {
      const dots = dotsContainer.querySelectorAll('.carousel-dot');
      dots.forEach((dot, idx) => {
        dot.classList.toggle('active', idx === currentIndex);
      });
    }
  }

  function scrollToReview(index) {
    track.scrollTo({ left: index * cardWidth, behavior: 'smooth' });
    currentIndex = index;
    updateControls();
  }

  function nextReview() {
    currentIndex++;
    if (currentIndex >= totalReviews) currentIndex = 0; // Loop back to start
    scrollToReview(currentIndex);
  }

  function startAutoScroll() {
    if (autoScrollInterval) clearInterval(autoScrollInterval);
    autoScrollInterval = setInterval(nextReview, 3500); // Scrolls every 3.5 seconds
  }

  function stopAutoScroll() {
    clearInterval(autoScrollInterval);
  }

  function updatePlayPauseIcon() {
    if (playPauseBtn) {
      playPauseBtn.innerHTML = isUserPaused ? '<i class="fa-solid fa-play"></i>' : '<i class="fa-solid fa-pause"></i>';
    }
  }

  // Initialize
  updateControls();
  startAutoScroll();

  // 3. Event Listeners
  
  // Play/Pause Button
  if (playPauseBtn) {
    playPauseBtn.addEventListener('click', () => {
      isUserPaused = !isUserPaused;
      updatePlayPauseIcon();
      if (isUserPaused) stopAutoScroll();
      else startAutoScroll();
    });
  }

  // Arrows (Manually clicking an arrow stops the auto-scroll so they can read)
  const prevBtn = document.getElementById('prevReview');
  const nextBtn = document.getElementById('nextReview');

  if(nextBtn) nextBtn.addEventListener('click', () => {
    isUserPaused = true; updatePlayPauseIcon();
    nextReview();
  });
  
  if(prevBtn) prevBtn.addEventListener('click', () => {
    isUserPaused = true; updatePlayPauseIcon();
    currentIndex--;
    if(currentIndex < 0) currentIndex = totalReviews - 1;
    scrollToReview(currentIndex);
  });

  // Pause scrolling while hovering over a review
  track.addEventListener('mouseenter', stopAutoScroll);
  track.addEventListener('mouseleave', () => {
    if(!isUserPaused) startAutoScroll();
  });

  // Sync dots/counter if user swipes manually on mobile
  track.addEventListener('scroll', () => {
    const newIndex = Math.round(track.scrollLeft / cardWidth);
    if (newIndex !== currentIndex && newIndex < totalReviews) {
      currentIndex = newIndex;
      updateControls();
    }
  });

  // "Show More" Expand Logic
  document.querySelectorAll('.show-more-btn').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const textElement = e.target.previousElementSibling;
      textElement.classList.toggle('expanded');
      e.target.innerText = textElement.classList.contains('expanded') ? 'Show less' : 'Show more';
      // Stop auto-scroll when they expand a review to read it!
      isUserPaused = true;
      updatePlayPauseIcon();
      stopAutoScroll(); 
    });
  });
});